function solve(points, target) {
    // Helper function to convert a point array to a string key for easy Set lookups
    const pointToKey = (p) => `${p[0]},${p[1]},${p[2]}`;

    // --- Check k=0 ---
    const initialPointsSet = new Set();
    for (const p of points) {
        initialPointsSet.add(pointToKey(p));
    }

    const targetKey = pointToKey(target);
    if (initialPointsSet.has(targetKey)) {
        return 0;
    }

