    // The process generates new points until the target is found or no new points can be generated.
    // Given the constraints (0 to 6), the number of unique reachable points is small (7^3 = 343).
    // The number of generations should not exceed a small constant.
    let k = 0;
    const maxIterations = 300; // Safety break, although the point space is small

    while (k < maxIterations) {
        k++;

        // Set to store the new points generated in this generation (k)
        const nextGenerationPoints = [];
        const currentPointsSet = new Set(currentPoints.map(pointToKey));
        const uniqueCurrentPoints = Array.from(currentPointsSet).map(key => key.split(',').map(Number));

        // Check if we can generate any new points.
        if (uniqueCurrentPoints.length < 2) {
            // If there are 0 or 1 unique points, no pairs can be formed.
            return -1;
        }

        let newPointsGenerated = false;

        // Iterate over all unique pairs of points from the current set
        for (let i = 0; i < uniqueCurrentPoints.length; i++) {
            for (let j = i + 1; j < uniqueCurrentPoints.length; j++) {
                const p1 = uniqueCurrentPoints[i];
                const p2 = uniqueCurrentPoints[j];

                // Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
                const cx = Math.floor((p1[0] + p2[0]) / 2);
                const cy = Math.floor((p1[1] + p2[1]) / 2);
                const cz = Math.floor((p1[2] + p2[2]) / 2);

