func solve(points [][]int64, target []int64) int64 {
	// Helper function to convert a point array to a string key for easy Set lookups
	pointToKey := func(p []int64) string {
		return string(rune(p[0])) + "," + string(rune(p[1])) + "," + string(rune(p[2]))
	}

	// Convert points to a set for O(1) lookup of initial points
	initialPointsSet := make(map[string]bool)
	for _, p := range points {
		key := pointToKey(p)
		initialPointsSet[key] = true
	}

	targetKey := pointToKey(target)
	if initialPointsSet[targetKey] {
		return 0
	}

	// currentPoints will store all unique points from Gen 0 up to the latest generation found.
	// We use a map to keep track of unique points efficiently.
	currentPointsMap := make(map[string][]int64)
	for _, p := range points {
		currentPointsMap[pointToKey(p)] = p
	}

	// k starts at 0 (Gen 0 is initial). We check for Gen 1, Gen 2, ...
	k := int64(0)

	for {
		k++

		// 1. Collect all unique points from Gen 0 to Gen k-1.
		// These are the keys in currentPointsMap.
		currentPointsList := make([][]int64, 0, len(currentPointsMap))
		for _, p := range currentPointsMap {
			currentPointsList = append(currentPointsList, p)
		}

		if len(currentPointsList) < 2 {
			// Not enough unique points to form a pair.
			return -1
		}

		// Set to store the keys of newly generated points in this generation (k)
		newPointsKeys := make(map[string]bool)
		nextGenerationPoints := make(map[string][]int64)

		// 2. Iterate over all unique pairs of points from the current set (Gen 0 to Gen k-1)
		n := len(currentPointsList)
		for i := 0; i < n; i++ {
			for j := i + 1; j < n; j++ {
				p1 := currentPointsList[i]
				p2 := currentPointsList[j]

				// Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
				cx := (p1[0] + p2[0]) / 2
				cy := (p1[1] + p2[1]) / 2
				cz := (p1[2] + p2[2]) / 2

				newPoint := []int64{cx, cy, cz}
				newPointKey := pointToKey(newPoint)

				// 3. Check if this new point is new (i.e., not present in Gen 0 to Gen k-1)
				if !currentPointsMap[newPointKey] {
					newPointsKeys[newPointKey] = true
					nextGenerationPoints[newPointKey] = newPoint
				}
			}
		}

		if len(nextGenerationPoints) == 0 {
			// No new unique points were generated in this generation.
			// Since the target wasn't found in previous generations, it cannot be found now or later.
			return -1
		}

		// 4. Add newly generated unique points to the pool for the next iteration (Gen k)
		for key, p := range nextGenerationPoints {
			currentPointsMap[key] = p
		}

		// 5. Check if the target was generated in this generation (k)
		if _, exists := nextGenerationPoints[targetKey]; exists {
			return k
		}
	}
}
