// Point represents a 3D point.
type Point struct {
	X, Y, Z int64
}

// pointToKey converts a Point to a unique string key.
func pointToKey(p Point) string {
	return string(p.X) + "," + string(p.Y) + "," + string(p.Z)
}

// solve finds the minimum generation k such that target is present in the set of points generated up to generation k.
func solve(points [][]int64, target []int64) int64 {
	// Convert initial points to a set for quick lookups and maintain a list for iteration.
	initialPointsSet := make(map[string]bool)
	var currentPoints []Point

	for _, pArr := range points {
		p := Point{X: pArr[0], Y: pArr[1], Z: pArr[2]}
		key := pointToKey(p)
		initialPointsSet[key] = true
		currentPoints = append(currentPoints, p)
	}

	targetPoint := Point{X: target[0], Y: target[1], Z: target[2]}
	targetKey := pointToKey(targetPoint)

	// Check k=0
	if initialPointsSet[targetKey] {
		return 0
	}

	// Use a map to track all unique points generated so far (Gen 0 up to Gen k-1)
	// This acts as the set of available points.
	allUniquePoints := make(map[string]Point)
	for _, p := range currentPoints {
		allUniquePoints[pointToKey(p)] = p
	}

	k := int64(0)
	// Since coordinates are small (0-6), the number of unique reachable points is at most 7^3 = 343.
	// The process must terminate relatively quickly, either by finding the target or by running out of new points.
	// A safety break around 344 iterations is sufficient.
	const maxGenerations = 350

	for k < maxGenerations {
		k++

		// Set to store the points generated in this specific generation (k)
		nextGenerationPoints := []Point{}
		newPointsGenerated := false

		// Convert the set of currently known points into a slice for indexed iteration.
		// Iterating over a map is non-deterministic, but since we are generating pairs, 
		// we just need all unique points from previous generations.
		var uniqueCurrentPoints []Point
		for _, p := range allUniquePoints {
			uniqueCurrentPoints = append(uniqueCurrentPoints, p)
		}

		N := len(uniqueCurrentPoints)

		// If fewer than 2 unique points exist, we cannot generate new points.
		if N < 2 {
			return -1
		}

		// Iterate over all unique pairs (a, b) from the set of points available up to Gen k-1
		for i := 0; i < N; i++ {
			for j := i + 1; j < N; j++ {
				p1 := uniqueCurrentPoints[i]
				p2 := uniqueCurrentPoints[j]

				// Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
				// Go's integer division truncates towards zero, which acts as floor for positive numbers.
				// Since coordinates are non-negative (0-6), standard integer division works for floor.
				cx := (p1.X + p2.X) / 2
				cy := (p1.Y + p2.Y) / 2
				cz := (p1.Z + p2.Z) / 2

				newPoint := Point{X: cx, Y: cy, Z: cz}
				newPointKey := pointToKey(newPoint)

				// Check if this new point is truly novel (not in allUniquePoints yet)
				if _, exists := allUniquePoints[newPointKey]; !exists {
					nextGenerationPoints = append(nextGenerationPoints, newPoint)
					newPointsGenerated = true
				}
			}
		}

		// Check if the target was generated in this step (k)
		for _, newPoint := range nextGenerationPoints {
			if newPoint.X == targetPoint.X && newPoint.Y == targetPoint.Y && newPoint.Z == targetPoint.Z {
				return k
			}
		}

		// Add all newly generated points to the pool for the next generation
		for _, p := range nextGenerationPoints {
			key := pointToKey(p)
			allUniquePoints[key] = p
		}

		// If no new unique points were generated, we are stuck.
		if !newPointsGenerated {
			return -1
		}
	}

	// Should be unreachable if the constraints are small enough, but acts as a final safeguard.
	return -1
}
